// Name: endSession.
// Description: Ends the current session.
function endSession() {
  console.log("[LEXI] endSession called.");
  window.lexi.speak.ptt.disablePTT();
  window.lexi.speak.ptt.hidePTT(true);
  window.lexi.speak.orb.setVoiceOrbState("idle");
}

// Name: startTimer.
// Description: Starts a countdown timer for the specified duration.
// Parameters:
//   params (object): Timer configuration object with the following properties:
//     - minutes (number): The number of minutes. Can be zero if less than 1 minute.
//     - seconds (number): The number of seconds.
//     - message (string): The message to display on the timer. Default: "You have some time to prepare."

function startTimer(params) {
  console.log("[LEXI] startTimer called.");

  // Extract parameters with defaults
  const minutes = params.minutes || 0;
  const seconds = (params.seconds || 0) + 5;
  const message = params.message || "You have some time to prepare.";

  // Log params
  console.log("[LEXI] startTimer called with params:", {
    minutes,
    seconds,
    message,
  });

  let timeoutId; // Declare at the top

  // Handler function for the event
  const handler = () => {
    clearTimeout(timeoutId);

    const chatbotId = window.lexi.speak.botId.main;
    setTimeout(() => {
      const prompt1 =
        "[System: Timer started] Tell the user that the timer has already started and they have some time to prepare (do not run `startTimer` again).";

      // window.lexi.utils.playSound("message_send");
      window.lexi.speak.orb.setVoiceOrbState("processing");
      window.lexi.utils.controlChatbot(
        chatbotId,
        false,
        prompt1,
        true,
        false,
        true,
        null
      );
    }, 1000); // Delay 1 second to wait for the question card.

    setTimeout(() => {
      window.lexi.utils.startTimer(minutes, seconds, message, () => {
        const prompt2 =
          "[System: Time's up] Tell the user to answer the question now.";

        setTimeout(() => {
          window.lexi.utils.playSound("message_send");
          window.lexi.speak.orb.setVoiceOrbState("processing");
          window.lexi.utils.controlChatbot(
            chatbotId,
            false,
            prompt2,
            true,
            false,
            true,
            null
          );
        }, 1000); // Delay 1 second to wait for animaton + sound effect to finish.

        console.log("Timer Completed!");
      });
    }, 0);
  };

  // Add the event listener
  setTimeout(() => {
    document.addEventListener("aietts:tts-ended", handler, { once: true });
  }, 2000);

  // Remove the listener after 60 seconds if not triggered
  timeoutId = setTimeout(() => {
    document.removeEventListener("aietts:tts-ended", handler); // Fixed to match
    console.log("[LEXI] startTimer: Listener removed after 60s timeout.");
  }, 60000);
}

// Name: updateTitle.
// Description: Updates the title of the conversation.
// Parameters:
//   title (string): The new title to set.
function updateTitle(title) {
  if (!title || title.trim() === "") {
    return;
  }
  window.lexi.utils.header.revealTag(false);

  setTimeout(() => {
    let displayTitle = title;
    if (displayTitle.length > 25) {
      displayTitle = displayTitle.substring(0, 22) + "...";
    }
    window.lexi.utils.header.setTag(displayTitle);
    window.lexi.utils.header.revealTag(true);
  }, 1000);
}


